INSERT INTO seen_jobs (job_id, source, status)
VALUES ($1, $2, 'new')
ON CONFLICT (job_id) DO UPDATE SET last_updated = NOW();

parameters.jsCode:
const NL = String.fromCharCode(10);
const items = $input.all();
const r = (items[0] && items[0].json) || {};
const date = r.date || new Date().toISOString().split('T')[0];
const review = r.review || {};
const build = r.build || {};
let slackWebhookUrl = '';
function tryNode(name) { try { const n = $(name).first(); return (n && n.json && n.json.slackWebhookUrl) || ''; } catch (e) { return ''; } }
slackWebhookUrl = tryNode('Config');
// Empty = Slack disabled; the notify node then posts to a dead URL with neverError on.
const lines = [':dart: *Job scrape run - ' + date + '*'];
if (review.error) {
  lines.push('Review FAILED: ' + review.error);
  if (review.stderr) lines.push('```' + String(review.stderr).slice(0, 1000) + '```');
} else {
  const scraped = (review.scraped != null) ? review.scraped : 0;
  const top = (review.top != null) ? review.top : 0;
  const second = (review.second != null) ? review.second : 0;
  const rejected = (review.rejected != null) ? review.rejected : 0;
  lines.push('Scraped: ' + scraped + '  -  Top: ' + top + '  -  Second: ' + second + '  -  Rejected: ' + rejected);
}
const packages = (build && Array.isArray(build.packages)) ? build.packages : [];
if (packages.length > 0) {
  lines.push('');
  lines.push('*Packages built:*');
  for (const p of packages) { lines.push('- ' + (p.title || '?') + ' @ ' + (p.company || '?')); }
} else if (build && build.error) {
  lines.push('');
  lines.push('Build FAILED: ' + build.error);
}
const message = lines.join(NL);
return [{ json: { message, slackWebhookUrl, date, review, build } }];
